CREATE INDEX idx_evo_nodes_latest ON evo_nodes(user_id, agent_id, is_latest, status);

CREATE INDEX idx_evo_nodes_scope ON evo_nodes(user_id, agent_id);

-- ---- evomem/integrity.py ----

CREATE TABLE integrity_check_runs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    ts TEXT NOT NULL,                 -- ISO8601 check time
    day TEXT NOT NULL,                -- local YYYY-MM-DD
    source TEXT NOT NULL,             -- startup | daily-tick | ...
    violation_count INTEGER NOT NULL, -- REAL findings only (injected drills excluded)
    structural_count INTEGER NOT NULL,
    created_at TEXT NOT NULL
);

CREATE INDEX idx_integrity_check_runs_day ON integrity_check_runs(day DESC);
